package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.fail;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class UnsafeAllocatorTest {

  @Test
  void testAssertInstantiable_withInstantiableClass() throws Exception {
    Method method = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    method.setAccessible(true);

    // Using a known instantiable class (e.g., String)
    try {
      method.invoke(null, String.class);
    } catch (InvocationTargetException e) {
      // If the method throws, unwrap and fail
      fail("assertInstantiable threw an exception for instantiable class: " + e.getCause());
    }
  }

  @Test
  void testAssertInstantiable_withNonInstantiableClass() throws Exception {
    Method method = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    method.setAccessible(true);

    // We need to simulate ConstructorConstructor.checkInstantiable returning non-null
    // This requires temporarily mocking ConstructorConstructor.checkInstantiable via reflection

    // Save original method
    Method checkInstantiableMethod = ConstructorConstructor.class.getDeclaredMethod("checkInstantiable", Class.class);
    checkInstantiableMethod.setAccessible(true);

    // Replace the method with a lambda returning a non-null string using a proxy or similar approach is complicated.
    // Instead, create a dummy class that is non-instantiable and triggers the exception message.

    class AbstractClass {
      AbstractClass() {}
    }

    // Because we cannot mock static methods easily without external libraries like PowerMock,
    // and ConstructorConstructor.checkInstantiable is private static, we test with a known non-instantiable class.

    // Use an interface, which is non-instantiable and should cause checkInstantiable() to return a message.
    Class<?> nonInstantiable = Runnable.class;

    AssertionError thrown = assertThrows(AssertionError.class,
        () -> method.invoke(null, nonInstantiable),
        "Expected assertInstantiable to throw AssertionError for non-instantiable class");

    // InvocationTargetException wraps the AssertionError, so unwrap:
    try {
      method.invoke(null, nonInstantiable);
      fail("Expected AssertionError");
    } catch (InvocationTargetException e) {
      Throwable cause = e.getCause();
      if (!(cause instanceof AssertionError)) {
        fail("Expected AssertionError but got " + cause);
      }
    }
  }
}
